c.clean:
#define solve __glifex_ref_clean
#include "solution.h"

static int cmpc(const void *a, const void *b) { return *(const char *)a - *(const char *)b; }

JVal *solve(JVal *c) {
    char *s = jstrdup(jget(c, "s")->str), *t = jstrdup(jget(c, "t")->str);
    size_t ls = strlen(s), lt = strlen(t);
    if (ls != lt) return jbool_(0);
    qsort(s, ls, 1, cmpc); qsort(t, lt, 1, cmpc);
    return jbool_(!strcmp(s, t));
}

c.optimized:
#define solve __glifex_ref_optimized
#include "solution.h"

JVal *solve(JVal *c) {
    const char *s = jget(c, "s")->str, *t = jget(c, "t")->str;
    if (strlen(s) != strlen(t)) return jbool_(0);
    int count[256] = {0};
    for (const unsigned char *p = (const unsigned char *)s; *p; p++) count[*p]++;
    for (const unsigned char *p = (const unsigned char *)t; *p; p++)
        if (--count[*p] < 0) return jbool_(0);
    return jbool_(1);
}

support.harness.c:
/* Generated harness — do not edit. Reads ../test_cases.json, dispatches on variant. */
#define _POSIX_C_SOURCE 200809L  /* clock_gettime under strict -std=c11 */
#include "solution.h"
#include <time.h>

/* Practice slot: the same "solve" name every language in this Lab uses
   -- see solution.h's own contract comment. clean.c/optimized.c ALSO
   define "solve" (matching that same convention, so the reference panel
   shows clean, copyable code) but rename their OWN symbol away from the
   bare name via a `#define solve __glifex_ref_<variant>` line at the top
   of each file, so all three can be compiled and linked together
   without colliding -- practice.c's real, unrenamed "solve" is the only
   one left with that name in the final binary. */
JVal *solve(JVal *c);
/* Weak DEFINITION, not a bare declaration: an undefined weak reference
   links to zero on ELF (Linux) but is an "Undefined symbols" link error
   on Mach-O (macOS) and PE (MinGW). A weak definition links cleanly on all
   three and is overridden by the strong symbol in brute-force.c when the
   problem ships one. */
JVal *__glifex_ref_bruteforce(JVal *c) __attribute__((weak));
JVal *__glifex_ref_bruteforce(JVal *c) { (void)c; fprintf(stderr, "brute-force reference not provided\n"); exit(2); }
JVal *__glifex_ref_clean(JVal *c);
JVal *__glifex_ref_optimized(JVal *c);

static char *read_file(const char *path) {
    printf("[BEFORE-OPEN] %s\n", path); fflush(stdout);
    FILE *f = fopen(path, "rb");
    if (!f) { fprintf(stderr, "cannot open %s\n", path); exit(2); }
    printf("[AFTER-OPEN]\n"); fflush(stdout);
    fseek(f, 0, SEEK_END); long n = ftell(f); rewind(f);
    char *buf = malloc(n + 1);
    if (fread(buf, 1, n, f) != (size_t)n) { fprintf(stderr, "read error\n"); exit(2); }
    buf[n] = 0; fclose(f);
    printf("[AFTER-READ] len=%ld\n", n); fflush(stdout);
    return buf;
}

#ifdef __wasm__
/* L4 space: counters DEFINED here; the -include'd gx_prelude.h declares them
   extern and routes every allocation through the tracking wrappers. */
long __gx_live = 0, __gx_peak = 0;
static volatile size_t __gx_sink = 0;
#endif

int main(int argc, char **argv) {
    printf("[MAIN-START]\n"); fflush(stdout);
    const char *variant = argc > 1 ? argv[1] : "practice";
    int bench = argc > 2 && !strcmp(argv[2], "--bench");
    char *raw = read_file("../test_cases.json");
    JVal *cases = json_parse(raw);
    printf("[AFTER-JSON-PARSE] n=%d\n", cases->n); fflush(stdout);
    JVal *(*fn)(JVal *) = !strcmp(variant, "practice") ? solve
                        : !strcmp(variant, "brute-force") ? __glifex_ref_bruteforce
                        : !strcmp(variant, "clean") ? __glifex_ref_clean : __glifex_ref_optimized;
    if (bench) {
        double best = 1e18;
        for (int r = 0; r < 5; r++) {
            struct timespec t0, t1;
            clock_gettime(CLOCK_MONOTONIC, &t0);
            for (int i = 0; i < cases->n; i++) fn(jget(cases->items[i], "input"));
            clock_gettime(CLOCK_MONOTONIC, &t1);
            double per = ((t1.tv_sec - t0.tv_sec) * 1e9 + (t1.tv_nsec - t0.tv_nsec)) / (cases->n > 0 ? cases->n : 1);
            if (per < best) best = per;
        }
        printf("  %s: ~%lld ns/case (coarse)\n", variant, (long long)best);
        return 0;
    }
    int metrics = argc > 2 && !strcmp(argv[2], "--metrics");   /* L1-metrics-c */
    int passed = 0;
    for (int i = 0; i < cases->n; i++) {
        JVal *in = jget(cases->items[i], "input");
        /* Diagnostic breadcrumb: flushed immediately, before any work on
           this case, so a crash mid-case still leaves a record of
           exactly how far processing got (which case, and by cross-
           referencing the Lab's ladder, roughly what input size) --
           the alternative is a crash with no indication of where in a
           30+-case Analyze run it happened. */
        printf("[CASE-BEGIN] case %d\n", i); fflush(stdout);
        char *got = jdumps(fn(in));
        if (metrics) {
#ifdef __wasm__
            /* L4 space: peak concurrent heap bytes (bracket the solve with a peak
               reset; the result pointer is consumed so the call is never elided),
               plus a bounded stack poison-scan. Gated to the wasm build; native
               gcc verify never compiles this. */
            {
                long __hbase = __gx_live; __gx_peak = __gx_live;
                JVal *__r = fn(in); __gx_sink ^= (size_t)(void *)__r;
                long __gxh = __gx_peak - __hbase;
                long __gxs = 0;
                {
                    /* Poison a window BELOW the current frame, run the solve, and see
                       how deep it was overwritten. Self-bounding: cap the window to
                       (sp - guard) so it can never underflow past address 0 and trap,
                       which is what a fixed window did on WASIX's low-placed stack. */
                    volatile char __probe; char *__sp = (char *)&__probe;
                    long __win = 96 * 1024;
                    long __avail = (long)(unsigned long)__sp - 8192;
                    if (__win > __avail) __win = __avail;
                    if (__win >= 4096) {
                        memset(__sp - __win, 0xA5, __win);
                        JVal *__r2 = fn(in); __gx_sink ^= (size_t)(void *)__r2;
                        for (long k = 0; k < __win; k++)
                            if ((unsigned char)(__sp - __win)[k] != 0xA5) { __gxs = __win - k; break; }
                    }
                }
                printf("  [SPACE] case %d heap=%ld stack=%ld\n", i, __gxh, __gxs);
            }
#endif
            /* Complexity Lab: per-case cost, adaptively repeated past the
               clock grain (solve is pure by the corpus contract); compile
               and startup are excluded by construction. */
            long long reps = 1, el = 0;
            for (;;) {
                struct timespec t0, t1;
                clock_gettime(CLOCK_MONOTONIC, &t0);
                for (long long r = 0; r < reps; r++) fn(in);
                clock_gettime(CLOCK_MONOTONIC, &t1);
                el = (t1.tv_sec - t0.tv_sec) * 1000000000LL + (t1.tv_nsec - t0.tv_nsec);
                if (el >= 2000000LL || reps >= 1048576) break;
                reps *= 2;
            }
            if (el > 0) printf("  [METRIC] case %d ns=%lld\n", i, el / reps);
        }
        char *exp = jdumps(jget(cases->items[i], "expected"));
        int ok = !strcmp(got, exp);
        passed += ok;
        printf("  [%s] case %d", ok ? "PASS" : "FAIL", i);
        if (!ok) printf("  expected=%s got=%s", exp, got);
        printf("\n");
    }
    printf("%d/%d passed\n", passed, cases->n);
    return passed == cases->n ? 0 : 1;
}

support.json.h:
/* Minimal JSON parser (C has no stdlib JSON). Vendored, dependency-free.
 * Short-lived test process: allocations are intentionally not freed. */
#pragma once
#include <ctype.h>
#include <math.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef enum { J_NULL, J_BOOL, J_NUM, J_STR, J_ARR, J_OBJ } JType;

typedef struct JVal {
    JType type;
    int b;
    double num;
    char *str;
    struct JVal **items;   /* arrays */
    char **keys;           /* objects */
    struct JVal **vals;
    int n;
} JVal;

static const char *jp;

static JVal *jnew(JType t) { JVal *v = calloc(1, sizeof(JVal)); v->type = t; return v; }
static void jws(void) { while (*jp && isspace((unsigned char)*jp)) jp++; }

static char *jstr_(void) {
    jp++; /* opening quote */
    /* Find this string's actual length (source chars, an always-safe
       upper bound on output length since escapes only ever shrink)
       instead of malloc(strlen(jp) + 1), which previously sized the
       buffer to the ENTIRE remaining unparsed JSON -- not just this
       one string. That's fine for a single small string, but this
       process's allocations are intentionally never freed (see file
       header), so the waste compounds across every string field in
       the input: a large multi-case payload could allocate many
       times its own size before finishing. Must skip escape pairs
       the same way the unescape loop below does, so an escaped quote
       (\") isn't mistaken for the closing one. */
    const char *start = jp;
    size_t srclen = 0;
    while (start[srclen] != '"') {
        if (start[srclen] == '\\') srclen++;
        srclen++;
    }
    char *buf = malloc(srclen + 1); int n = 0;
    while (*jp != '"') {
        char c = *jp++;
        if (c == '\\') { char e = *jp++; buf[n++] = e == 'n' ? '\n' : e == 't' ? '\t' : e; }
        else buf[n++] = c;
    }
    jp++; buf[n] = 0; return buf;
}

static JVal *jvalue(void);

static JVal *jvalue(void) {
    jws();
    if (*jp == '{') {
        JVal *v = jnew(J_OBJ); jp++; jws();
        if (*jp == '}') { jp++; return v; }
        int cap = 8; v->keys = malloc(cap * sizeof(char *)); v->vals = malloc(cap * sizeof(JVal *));
        while (1) {
            jws(); char *k = jstr_(); jws(); jp++; /* ':' */
            if (v->n == cap) { cap *= 2; v->keys = realloc(v->keys, cap * sizeof(char *)); v->vals = realloc(v->vals, cap * sizeof(JVal *)); }
            v->keys[v->n] = k; v->vals[v->n] = jvalue(); v->n++;
            jws(); if (*jp == ',') { jp++; continue; } jp++; break;
        }
        return v;
    }
    if (*jp == '[') {
        JVal *v = jnew(J_ARR); jp++; jws();
        if (*jp == ']') { jp++; return v; }
        int cap = 8; v->items = malloc(cap * sizeof(JVal *));
        while (1) {
            if (v->n == cap) { cap *= 2; v->items = realloc(v->items, cap * sizeof(JVal *)); }
            v->items[v->n++] = jvalue();
            jws(); if (*jp == ',') { jp++; continue; } jp++; break;
        }
        return v;
    }
    if (*jp == '"') { JVal *v = jnew(J_STR); v->str = jstr_(); return v; }
    if (*jp == 't') { JVal *v = jnew(J_BOOL); v->b = 1; jp += 4; return v; }
    if (*jp == 'f') { JVal *v = jnew(J_BOOL); v->b = 0; jp += 5; return v; }
    if (*jp == 'n') { jp += 4; return jnew(J_NULL); }
    JVal *v = jnew(J_NUM); char *end;
    v->num = strtod(jp, &end); jp = end; return v;
}

static JVal *json_parse(const char *src) { jp = src; return jvalue(); }

static JVal *jget(JVal *obj, const char *key) {
    for (int i = 0; i < obj->n; i++)
        if (!strcmp(obj->keys[i], key)) return obj->vals[i];
    return NULL;
}


/* Portable string builder (replaces POSIX open_memstream; works on MinGW). */
typedef struct { char *buf; size_t len, cap; } SB;
static void sb_put(SB *sb, const char *s) {
    size_t n = strlen(s);
    if (sb->len + n + 1 > sb->cap) {
        sb->cap = (sb->cap ? sb->cap * 2 : 128) + n;
        sb->buf = realloc(sb->buf, sb->cap);
    }
    memcpy(sb->buf + sb->len, s, n + 1); sb->len += n;
}

static void jdump_sb(JVal *v, SB *out) {
    char tmp[64];
    switch (v->type) {
        case J_NULL: sb_put(out, "null"); break;
        case J_BOOL: sb_put(out, v->b ? "true" : "false"); break;
        case J_NUM: {
            double ip;
            if (modf(v->num, &ip) == 0.0) snprintf(tmp, sizeof tmp, "%lld", (long long)v->num);
            else snprintf(tmp, sizeof tmp, "%g", v->num);
            sb_put(out, tmp); break; }
        case J_STR: sb_put(out, "\""); sb_put(out, v->str); sb_put(out, "\""); break;
        case J_ARR: sb_put(out, "[");
            for (int i = 0; i < v->n; i++) { if (i) sb_put(out, ","); jdump_sb(v->items[i], out); }
            sb_put(out, "]"); break;
        case J_OBJ: sb_put(out, "{");
            for (int i = 0; i < v->n; i++) {
                if (i) sb_put(out, ",");
                sb_put(out, "\""); sb_put(out, v->keys[i]); sb_put(out, "\":");
                jdump_sb(v->vals[i], out);
            }
            sb_put(out, "}"); break;
    }
}

static char *jdumps(JVal *v) {
    SB sb = {0};
    sb_put(&sb, "");
    jdump_sb(v, &sb);
    return sb.buf;
}

/* Portable strdup (not in strict C11). */
static char *jstrdup(const char *s) {
    char *d = malloc(strlen(s) + 1); strcpy(d, s); return d;
}

