  const seen = new Map<number, number>();
  const nums = c.nums, n = nums.length;
  for (let i = 0; i < n; i++) {
    const need = c.target - nums[i];
    const idx = seen.get(need);
    if (idx !== undefined) return [idx, i];
    seen.set(nums[i], i);
  }
  return [];
}

