go.clean:
package main

// The professional default: slide a two-value window up the sequence, keeping
// only the pair the next term needs. One pass, no table, no recursion --
// O(n) time and O(1) space.
func clean(c map[string]any) any {
	n := int(c["n"].(float64))
	a, b := 0, 1
	for i := 0; i < n; i++ {
		a, b = b, a+b
	}
	return a
}

go.optimized:
package main

// Same O(n) window slide as clean, unrolled 2x: each iteration advances two
// Fibonacci steps, so the loop counter is checked half as often and the two
// halves of the pair never need a temporary swap. Peeling one step when n is
// odd keeps the remaining count even. This mirrors the 8080 optimized.s's
// peel-odd-n + unrolled-pair trick (see that file for the full derivation) --
// a genuine constant-factor win that stays inside the declared O(n) class.
func optimized(c map[string]any) any {
	n := int(c["n"].(float64))
	a, b := 0, 1
	if n&1 == 1 {
		a, b = b, a+b
		n--
	}
	for n > 0 {
		t := a + b
		b = t + b
		a = t
		n -= 2
	}
	return a
}

go.brute-force:
package main

// fibRec is the recurrence transcribed literally: fib(n) = fib(n-1) + fib(n-2).
// It recomputes the same subproblems exponentially many times -- fib(n-2) is
// evaluated once for fib(n) and again inside fib(n-1) -- which is exactly what
// clean's single pass exists to avoid.
func fibRec(n int) int {
	if n < 2 {
		return n
	}
	return fibRec(n-1) + fibRec(n-2)
}

// Obvious approach: the naive recursive definition. O(phi^n) time, and the
// call stack reaches depth n, so O(n) space.
func bruteForce(c map[string]any) any {
	n := int(c["n"].(float64))
	return fibRec(n)
}

